parameters.jsCode:
// Merge Buyer Contacts into Scored Accounts rows, joined on Company Domain.
//
// Clay cannot write enrichment results back to its source Google Sheet.
// Workaround: Clay exports Find Person results to a separate 'Buyer Contacts' tab.
// This node joins them here in n8n before the rest of WF4 runs.
//
// Domain normalization strips protocol, www prefix, and path/query suffixes so
// that 'https://gong.io/', 'www.gong.io', and 'gong.io' all match each other.
// Without this, Clay-enriched contacts with slightly different domain formats
// silently fail to join and buyer fields remain empty downstream.

function normalizeDomain(d) {
  if (!d) return '';
  return String(d).trim().toLowerCase()
    .replace(/^https?:\/\//, '')
    .replace(/^www\./, '')
    .replace(/[/?#].*$/, '');
}

const accounts = $('Sheets — Get Enriched Accounts').all();
const contacts = $('Sheets — Get Buyer Contacts').all();

// Build a lookup map: normalized domain → first matching contact
const contactMap = {};
for (const c of contacts) {
  const domain = normalizeDomain(c.json['Company Domain']);
  if (domain && !contactMap[domain]) contactMap[domain] = c.json;
}

// Merge contact fields into each account row
const merged = accounts.map(a => {
  const domain  = normalizeDomain(a.json['Company Domain']);
  const contact = contactMap[domain] || {};
  return {
    json: {
      ...a.json,
      'Buyer Name':  a.json['Buyer Name']  || contact['Buyer Name']  || '',
      'Buyer Title': a.json['Buyer Title'] || contact['Buyer Title'] || '',
      'Buyer Email': a.json['Buyer Email'] || contact['Buyer Email'] || ''
    }
  };
});

return merged;

function normalizeDomain(d) {
  if (!d) return '';
  return String(d).trim().toLowerCase()
    .replace(/^https?:\/\//, '')
    .replace(/^www\./, '')
    .replace(/[/?#].*$/, '');
}

function sanitize(val) {
  if (val === null || val === undefined) return '';
  return String(val)
    .replace(/\"/g, "'")
    .replace(/\r?\n/g, ' ')
    .trim();
}

const current = $input.item.json;
const domain = normalizeDomain(current['Company Domain'] || current.company_domain || '');

const allAccounts = $('Code — Merge Buyer Contacts').all();
const account = allAccounts.find(
  a => normalizeDomain(a.json['Company Domain']) === domain
)?.json || {};

return {
  json: {
    'Company Name':     sanitize(account['Company Name']),
    'Company Domain':   account['Company Domain'] || current['Company Domain'] || '',
    'Employee Count':   account['Employee Count'] || '',
    'Funding Stage':    sanitize(account['Funding Stage']),
    'Estimated ARR':    sanitize(account['Estimated ARR']),
    'CS Headcount':     account['CS Headcount'] || '',
    'Tech Stack':       sanitize(account['Tech Stack']),
    'Signal Types':     sanitize(account['Signal Types']),
    'Signal Summaries': sanitize(account['Signal Summaries']),
    'Buyer Name':       sanitize(account['Buyer Name']),
    'Buyer Title':      sanitize(account['Buyer Title']),
    'Buyer Email':      account['Buyer Email'] || ''
  }
};

