parameters.jsCode:
// Parse OpenRouter JSON response and carry forward the full account row.
//
// Why domain-match lookup instead of $input:
// - $input at this point is the OpenRouter HTTP response.
// - The full account row (with merged buyer fields) lives at
//   'Code — Merge Buyer Contacts'. We reach it by node name.
// - When multiple enriched accounts are in the same execution batch,
//   we match by the domain that was marked 'Scoring In Progress'.

const response = $input.item.json;
const raw = response?.choices?.[0]?.message?.content || '{}';

let scores;
try {
  scores = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  scores = {
    firmographic_score: 0,
    signal_score: 0,
    tech_score: 0,
    total_score: 0,
    tier: 'Discard',
    reasoning: 'Parse error — check OpenRouter response format'
  };
}

const domain = $('Sheets — Mark Scoring In Progress').item.json['Company Domain'];
const allAccounts = $('Code — Merge Buyer Contacts').all();
const account = allAccounts.find(
  a => String(a.json['Company Domain']).trim().toLowerCase()
       === String(domain).trim().toLowerCase()
)?.json || {};

return {
  json: {
    company_domain:     account['Company Domain'] || domain,
    company_name:       account['Company Name'] || '',
    employee_count:     account['Employee Count'] || '',
    funding_stage:      account['Funding Stage'] || '',
    estimated_arr:      account['Estimated ARR'] || '',
    tech_stack:         account['Tech Stack'] || '',
    cs_headcount:       account['CS Headcount'] || '',
    signal_types:       account['Signal Types'] || '',
    signal_summaries:   account['Signal Summaries'] || '',
    buyer_name:         account['Buyer Name'] || '',
    buyer_title:        account['Buyer Title'] || '',
    buyer_email:        account['Buyer Email'] || '',
    firmographic_score: scores.firmographic_score ?? 0,
    signal_score:       scores.signal_score ?? 0,
    tech_score:         scores.tech_score ?? 0,
    total_score:        scores.total_score ?? 0,
    tier:               scores.tier || 'Discard',
    reasoning:          scores.reasoning || ''
  }
};

function normalizeDomain(d) {
  if (!d) return '';
  return String(d).trim().toLowerCase()
    .replace(/^https?:\/\//, '')
    .replace(/^www\./, '')
    .replace(/[/?#].*$/, '');
}

const current = $input.first().json;
const domain = normalizeDomain(
  current.company_domain || current['Company Domain'] || ''
);

const parsedItems = $('Code — Parse Score Result').all();
const scored = parsedItems.find(
  i => normalizeDomain(i.json.company_domain || i.json['Company Domain']) === domain
)?.json || current;

const allContacts = $('Sheets — Get Buyer Contacts').all();
const matching = allContacts.filter(c =>
  normalizeDomain(c.json['Company Domain']) === domain
);

if (matching.length === 0) {
  return [{ json: { ...scored } }];
}

return matching.map(c => ({
  json: {
    ...scored,
    buyer_name:  c.json['Buyer Name']  || scored.buyer_name  || '',
    buyer_title: c.json['Buyer Title'] || scored.buyer_title || '',
    buyer_email: c.json['Buyer Email'] || scored.buyer_email || ''
  }
}));
